#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const double PI = acos(-1.0);
    while(T--){
        long long n; scanf("%lld", &n);
        double angle = PI / n;
        double s = sin(angle);
        double ans = 1.0 / (s * s);
        printf("%.10f\n", ans);
    }
    return 0;
}

